extension DashboardL10nContext on BuildContext {
  /// Localized dashboard string; falls back to English if missing.
  String opsTr(String english) {
    final key = kDashboardEnglishToKey[english];
    if (key == null) return english;
    final lc = _dashboardLocaleLanguageCode(this);
    final langMap = kDashboardL10nByLang[lc];
    final enMap = kDashboardL10nByLang['en']!;
    return langMap?[key] ?? enMap[key] ?? english;
  }
}

String _dashboardLocaleLanguageCode(BuildContext context) {
  try {
    return ProviderScope.containerOf(context, listen: false).read(localeProvider).languageCode;
  } catch (_) {
    return Localizations.localeOf(context).languageCode;
  }
}
